import { ingestRequestSchema } from "@/lib/contracts";
import { AppError } from "@/lib/errors";
import { parseGithubRepoUrl } from "@/lib/github-url";
import { fail, toAppError } from "@/lib/http";

export async function POST(request: Request) {
  try {
    const body = ingestRequestSchema.parse(await request.json());
    parseGithubRepoUrl(body.repoUrl);

    return fail(
      new AppError(
        "not_implemented_stage1",
        "POST /api/repos/ingest is intentionally stubbed in Stage 1. Real GitHub metadata resolution and snapshot creation begin in Stage 2.",
        501
      )
    );
  } catch (error) {
    return fail(toAppError(error));
  }
}
