import { z } from "zod";
import { AppError } from "@/lib/errors";

const githubUrlSchema = z
  .string()
  .url()
  .refine((value) => {
    try {
      const url = new URL(value);
      return url.hostname === "github.com";
    } catch {
      return false;
    }
  }, "URL must point to github.com");

export type ParsedGithubRepoUrl = {
  repoUrl: string;
  canonicalUrl: string;
  owner: string;
  repo: string;
};

export function parseGithubRepoUrl(input: string): ParsedGithubRepoUrl {
  const repoUrl = githubUrlSchema.parse(input);

  const url = new URL(repoUrl);
  const segments = url.pathname.split("/").filter(Boolean);

  if (segments.length < 2) {
    throw new AppError(
      "invalid_repo_url",
      "The provided repository URL is not a valid public GitHub repository URL.",
      400
    );
  }

  const owner = segments[0];
  const repo = segments[1].replace(/\.git$/, "");

  if (!owner || !repo) {
    throw new AppError(
      "invalid_repo_url",
      "The provided repository URL is not a valid public GitHub repository URL.",
      400
    );
  }

  return {
    repoUrl,
    canonicalUrl: `https://github.com/${owner}/${repo}`,
    owner,
    repo
  };
}
